 type mockLogSink struct {
+	mu       sync.Mutex
 	received []struct {
 		taskID, stream, line string
 	}
 }

 func (m *mockLogSink) SendLog(taskID, stream, line string) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
 	m.received = append(m.received, struct {
 		taskID, stream, line string
 	}{taskID, stream, line})
 }

+func (m *mockLogSink) Len() int {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	return len(m.received)
+}
